/**
 * Viewer (PSV implementation)
 *
 * Uses Photo Sphere Viewer v4 + MarkersPlugin (same stack as your editor),
 * so camera feel + hotspot yaw/pitch coordinates match exactly.
 */

import { Floorplan } from './Floorplan.js';
import { Analytics } from './Analytics.js';
import { ApiService } from './ApiService.js';
import { resolveContainer } from './Utils.js';
import { ensurePsvAssets } from './ensurePsvAssets.js';

export class Viewer {
  constructor(options) {
    this.options = { enableVR: false, ...options };
    this.container = resolveContainer(this.options.container);
    this.container.classList.add('p360-root');

    this._destroyed = false;
    this._debug =
      !!this.options.debug ||
      (typeof window !== 'undefined' && !!window.__P360_DEBUG);

    const backendUrl =
      this.options.backendUrl ||
      this.options.backend_url ||
      this.options.apiBaseUrl ||
      'http://46.225.89.136/api';
    this.api = new ApiService({ baseUrl: backendUrl });
    this.analytics = new Analytics({ projectId: this.options.projectId });

    this._project = null;
    this._tourData = null;

    // Interior state
    this._interiors = [];
    this._interior = null;
    this._hudInteriorButtons = new Map();

    // Panoramas + floorplan
    this._panoramas = [];
    this._floorplans = [];
    this._currentPanoramaId = null;
    this._currentFloorplanId = null;

    // View mode (360 via PSV, 2d/3d via overlay images)
    this._viewMode = '360'; // '360' | '2d' | '3d'

    // Overlay state
    this._overlay = this._createOverlay();
    this._overlayMode = 'none';
    this._overlayUrls = [];
    this._overlayIndex = 0;
    this._topViewUrl = null;
    this._middleCutUrls = [];

    // PSV mount point (below HUD)
    this._psvEl = document.createElement('div');
    this._psvEl.className = 'p360-psv';
    Object.assign(this._psvEl.style, {
      position: 'absolute',
      inset: '0',
      zIndex: '1'
    });
    this.container.appendChild(this._psvEl);

    // HUD + floorplan overlay (your existing layout/CSS)
    this._hud = this._createHud();
    this.floorplan = new Floorplan({
      root: this.container,
      onNavigatePanorama: (id) => this._onFloorplanNavigate(id),
      onRoomClick: (room) => this._onFloorplanRoomClick(room),
      onRoomHover: (room) => this._onFloorplanRoomHover(room)
    });

    // PSV runtime
    this._PSV = null;
    this._psv = null;
    this._markers = null;
    this._gyro = null;
    this._stereo = null;

    // Bindings
    this._onPageHide = () => {
      if (this._destroyed) return;
      this.analytics.track('session_end', { panoramaId: this._currentPanoramaId, reason: 'pagehide' });
    };
    window.addEventListener('pagehide', this._onPageHide);
  }

  _dlog(...args) {
    if (!this._debug) return;
    // eslint-disable-next-line no-console
    console.debug('[Panorama360]', ...args);
  }

  async init() {
    await this.analytics.track('session_start', { userAgent: navigator.userAgent });
    this._PSV = await ensurePsvAssets();
    await this._loadProjectData();

    const startId =
      this._project?.settings?.start_panorama_id ||
      this._panoramas?.[0]?.id ||
      null;
    if (!startId) throw new Error('Panorama360: project has no panoramas');

    // Create PSV viewer (navbar disabled; we render our own HUD)
    const startPano = this._getPanoramaById(startId);
    if (!startPano?.image_url) throw new Error('Panorama360: start panorama has no image_url');

    const PSV = this._PSV;
    const plugins = [
      // Markers plugin for hotspots
      [PSV.MarkersPlugin, { markers: [] }]
    ];

    // Optional: gyroscope + stereo "VR mode" (mobile)
    if (PSV.GyroscopePlugin) plugins.unshift(PSV.GyroscopePlugin);
    if (PSV.StereoPlugin) plugins.unshift(PSV.StereoPlugin);

    this._psv = new PSV.Viewer({
      container: this._psvEl,
      panorama: startPano.image_url,
      navbar: false,
      // editor-like feel
      touchmoveTwoFingers: true,
      mousewheelCtrlKey: false,
      // Slightly more zoomed-out initial view.
      maxFov: 102,
      defaultZoomLvl: 35,
      plugins
    });

    this._markers = this._psv.getPlugin?.(PSV.MarkersPlugin) || null;
    this._gyro = this._psv.getPlugin?.('gyroscope') || this._psv.getPlugin?.(PSV.GyroscopePlugin) || null;
    this._stereo = this._psv.getPlugin?.('stereo') || this._psv.getPlugin?.(PSV.StereoPlugin) || null;

    if (this._markers?.on) {
      this._markers.on('select-marker', (e, marker) => {
        const m = marker || e?.args?.[0] || e?.marker || null;
        const id = m?.config?.id || m?.id || null;
        if (!id) return;
        const row = m?.config?.data || m?.data || null;
        if (row?.target_panorama_id) {
          this.loadPanorama(row.target_panorama_id, { reason: 'hotspot' }).catch(() => {});
        }
      });
    }

    // Sync HUD zoom label to actual PSV zoom.
    try {
      this._psv.once?.('ready', () => {
        const z = this._psv.getZoomLevel?.();
        if (typeof z === 'number' && this._btnZoom) {
          this._btnZoom.textContent = z <= 20 ? '1×' : (z <= 70 ? '1.5×' : '2×');
        }
      });
    } catch {
      // ignore
    }

    await this.loadPanorama(startId, { reason: 'initial' });
  }

  getViewYawPitch() {
    if (!this._psv?.getPosition) return { yaw: 0, pitch: 0 };
    const pos = this._psv.getPosition(); // radians
    const radToDeg = (r) => (r * 180) / Math.PI;
    const normYaw = (deg) => ((deg + 180) % 360 + 360) % 360 - 180;
    return { yaw: normYaw(radToDeg(pos.longitude)), pitch: radToDeg(pos.latitude) };
  }

  async enterVR() {
    // PSV v4 uses StereoPlugin as "VR-like" cardboard mode (requires gyroscope).
    if (!this._stereo?.start) throw new Error('Panorama360: VR mode is not available (Stereo plugin missing)');
    await this._stereo.start();
  }

  async exitVR() {
    if (!this._stereo?.stop) return;
    this._stereo.stop();
  }

  toggleFloorplan() {
    return this.floorplan?.toggle?.() || this.floorplan?.setVisible?.(!this.floorplan?.isVisible?.());
  }

  async loadPanorama(panoramaId, { reason = 'api' } = {}) {
    if (this._destroyed) return;
    const pano = this._getPanoramaById(panoramaId);
    if (!pano) throw new Error(`Panorama360: panorama not found: ${panoramaId}`);

    this._currentPanoramaId = pano.id;
    this._currentFloorplanId = pano.floorplan_id || null;

    // 2D/3D overlay modes
    if (this._viewMode !== '360') {
      this._applyOverlayMode(this._viewMode);
      return;
    }

    this._overlay.setVisible(false);
    this._psvEl.style.display = '';

    // Keep current position when switching interiors/panos (like editor)
    const keepPos = this._psv?.getPosition ? this._psv.getPosition() : null;

    // Load panorama in PSV
    if (this._psv?.setPanorama) {
      await this._psv.setPanorama(pano.image_url, {
        transition: 'fade',
        speed: '5rpm',
        // best-effort: keep current camera pose
        longitude: keepPos?.longitude,
        latitude: keepPos?.latitude
      });
    }

    // Hotspots for this panorama
    const hotspotRows = await this._getHotspotsByPanorama(pano.id);
    this._setHotspotsPsv(hotspotRows);

    // Floorplan data
    const fp =
      pano.floorplan_id
        ? this._getFloorplanById(pano.floorplan_id)
        : (this._floorplans[0] || null);
    await this.floorplan.setData(fp, this._panoramas);
    this.floorplan.setRoomMeta(this._getRoomMetaMapFromProject());
    this.floorplan.setActiveRoom((pano.room_id || this._getRoomIdForPanorama(pano)) || null);

    await this.analytics.track('panorama_loaded', { panoramaId: pano.id, reason, viewMode: this._viewMode });
    this._updateHudState?.();
  }

  async destroy() {
    if (this._destroyed) return;
    this._destroyed = true;
    window.removeEventListener('pagehide', this._onPageHide);
    try { await this.analytics.track('session_end', { panoramaId: this._currentPanoramaId }); } catch {}
    try { this._markers?.destroy?.(); } catch {}
    try { this._psv?.destroy?.(); } catch {}
    this.floorplan?.destroy?.();
    if (this._hud?.parentNode) this._hud.parentNode.removeChild(this._hud);
    if (this._psvEl?.parentNode) this._psvEl.parentNode.removeChild(this._psvEl);
  }

  // -----------------------------
  // Data mapping helpers (copied/adapted from previous Viewer)
  // -----------------------------

  async _loadProjectData() {
    const projectId = this.options.projectId;
    this._project = await this.api.getProject(projectId);
    this._tourData = this._project?.tour_data || null;

    this._interiors = this._getInteriorNamesFromProject(this._project);
    this._interior = this._pickDefaultInterior(this._interiors, this._project);
    this._panoramas = this._buildPanoramasForInterior(this._interior);
    this._floorplans = this._buildFloorplansFromProject(this._project);

    this._topViewUrl = this._inferTopViewUrl();
    this._middleCutUrls = await this._inferMiddleCutUrls();
    this._buildInteriorButtons?.();
    this._updateHudState?.();
  }

  _getInteriorNamesFromProject(project) {
    const images360 = project?.images?.['360'] || null;
    if (images360 && typeof images360 === 'object' && !Array.isArray(images360)) {
      return Object.keys(images360)
        .filter((k) => Array.isArray(images360?.[k]) && images360[k].length > 0)
        // Preserve backend JSON key order (matches your API response / editor expectation).
        // If you want alphabetical, sort at the backend instead.
        ;
    }
    return [];
  }

  _pickDefaultInterior(interiors) {
    if (Array.isArray(interiors) && interiors.length) return interiors[0];
    return null;
  }

  _getAssetUrl(asset) {
    if (!asset) return null;
    if (typeof asset === 'string') return asset.trim() || null;
    if (typeof asset?.publicUrl === 'string' && asset.publicUrl.trim()) return asset.publicUrl.trim();
    if (typeof asset?.url === 'string' && asset.url.trim()) return asset.url.trim();
    return null;
  }

  _getAssetName(asset) {
    if (!asset) return null;
    if (typeof asset?.fileName === 'string' && asset.fileName.trim()) return asset.fileName.trim();
    if (typeof asset?.name === 'string' && asset.name.trim()) return asset.name.trim();
    if (typeof asset?.path === 'string' && asset.path.trim()) return asset.path.trim().split('/').pop() || asset.path.trim();
    return null;
  }

  _getProjectImages(kind, interior = null) {
    const imgs = this._project?.images?.[kind] ?? null;
    if (!imgs) return [];
    if (Array.isArray(imgs)) return imgs;
    if (imgs && typeof imgs === 'object') {
      if (interior && Array.isArray(imgs?.[interior])) return imgs[interior];
      const firstKey = Object.keys(imgs).find((k) => Array.isArray(imgs?.[k]) && imgs[k].length) || null;
      if (firstKey) return imgs[firstKey];
    }
    return [];
  }

  _buildPanoramasForInterior(interior) {
    const projectId = this.options.projectId;
    const list = this._getProjectImages('360', interior);
    const isRaster = (name) => /\.(webp|jpe?g|png)$/i.test(String(name || '').split('?')[0]);

    const roomMap = this._project?.floorplan_data?.room_map && typeof this._project.floorplan_data.room_map === 'object'
      ? this._project.floorplan_data.room_map
      : null;
    const panoIdToRoomId = new Map();
    if (roomMap) {
      for (const [roomId, ref] of Object.entries(roomMap)) {
        if (!ref) continue;
        const file = String(ref).split('/').pop() || String(ref);
        panoIdToRoomId.set(file, roomId);
      }
    }

    if (Array.isArray(list) && list.length) {
      return list
        .map((asset) => {
          const url = this._getAssetUrl(asset);
          const fileName = this._getAssetName(asset);
          if (!url || !fileName || !isRaster(fileName)) return null;
          return {
            id: fileName,
            project_id: projectId,
            name: fileName,
            image_url: url,
            room_id: panoIdToRoomId.get(fileName) || null,
            floorplan_id: null,
            floorplan_x: null,
            floorplan_y: null
          };
        })
        .filter(Boolean)
        .slice()
        .sort((a, b) => String(a.id).localeCompare(String(b.id)));
    }

    // Fallback: derive from tour_data.scenes
    const scenes = this._tourData?.scenes && typeof this._tourData.scenes === 'object' ? this._tourData.scenes : {};
    return Object.values(scenes).map((scene) => ({
      id: scene.id,
      project_id: projectId,
      name: scene.name || null,
      image_url: scene.image || null,
      room_id: scene.roomId || scene.room_id || null,
      floorplan_id: null,
      floorplan_x: null,
      floorplan_y: null
    }));
  }

  _buildFloorplansFromProject(project) {
    const fp = project?.floorplan_data && typeof project.floorplan_data === 'object' ? project.floorplan_data : null;
    const floorplanAssets = project?.images?.floorplan;
    const assets = Array.isArray(floorplanAssets) ? floorplanAssets : [];
    const pickFromAssets = (extRe) => {
      for (const a of assets) {
        const name = this._getAssetName(a) || '';
        const url = this._getAssetUrl(a);
        if (url && extRe.test(name.split('?')[0] || name)) return url;
      }
      return null;
    };
    const imageUrl =
      (typeof fp?.image_url === 'string' && fp.image_url.trim() ? fp.image_url.trim() : null) ||
      pickFromAssets(/\.(png|jpe?g|webp)$/i) ||
      null;
    const svgUrl =
      (typeof fp?.svg_url === 'string' && fp.svg_url.trim() ? fp.svg_url.trim() : null) ||
      pickFromAssets(/\.svg$/i) ||
      null;
    if (!imageUrl) return [];
    return [{
      id: fp?.id || 'floorplan:0',
      project_id: this.options.projectId,
      image_url: imageUrl,
      svg_url: svgUrl,
      width: fp?.width || 1,
      height: fp?.height || 1
    }];
  }

  _getFloorplanById(id) {
    return this._floorplans.find((f) => f.id === id) || null;
  }

  _getPanoramaById(idOrRef) {
    if (!idOrRef) return null;
    const raw = String(idOrRef);
    const rawNoQuery = raw.split('?')[0];
    const ref = raw.toLowerCase();
    const refNoQuery = rawNoQuery.toLowerCase();
    const refFileNoQuery = (rawNoQuery.split('/').pop() || rawNoQuery).toLowerCase();
    return (
      this._panoramas.find((p) => String(p.id).toLowerCase() === ref) ||
      this._panoramas.find((p) => p.name && String(p.name).toLowerCase() === ref) ||
      this._panoramas.find((p) => {
        const u = (p.image_url || '').toString();
        const uNoQuery = u.split('?')[0];
        return u.toLowerCase() === ref || uNoQuery.toLowerCase() === refNoQuery;
      }) ||
      this._panoramas.find((p) => {
        const url = p.image_url || '';
        const filename = (url.split('/').pop() || '').toLowerCase();
        const filenameNoQuery = filename.split('?')[0];
        return (
          filename === ref ||
          filenameNoQuery === refNoQuery ||
          filenameNoQuery === refFileNoQuery
        );
      }) ||
      null
    );
  }

  async _getHotspotsByPanorama(panoramaId) {
    const tour = this._tourData || this._project?.tour_data || null;
    const scenes = tour?.scenes && typeof tour.scenes === 'object' ? tour.scenes : {};
    const scene = scenes?.[panoramaId] || Object.values(scenes).find((s) => s?.id === panoramaId) || null;
    const hs = Array.isArray(scene?.hotspots) ? scene.hotspots : [];
    const normYawDeg = (deg) => ((deg + 180) % 360 + 360) % 360 - 180;
    const clampPitchDeg = (deg) => Math.max(-90, Math.min(90, deg));
    return hs.map((h, idx) => ({
      id: `${panoramaId}::${idx}`,
      panorama_id: panoramaId,
      type: h?.type || 'navigate',
      yaw: normYawDeg(Number(h?.yaw ?? 0)),
      pitch: clampPitchDeg(Number(h?.pitch ?? 0)),
      target_panorama_id: h?.targetId || null,
      camera: h?.camera && typeof h.camera === 'object' ? h.camera : null,
      label: h?.label || null,
      preview: h?.preview || null
    }));
  }

  _setHotspotsPsv(rows) {
    if (!this._markers) return;
    try { this._markers.clearMarkers?.(); } catch {}
    for (const row of rows || []) {
      const id = row.id;
      const tooltip = row.label || '';
      // Use a simple circle marker like the editor (fast + consistent).
      // PSV v4 MarkersPlugin expects "longitude/latitude" (radians or strings like "10deg").
      this._markers.addMarker?.({
        id,
        position: { longitude: `${row.yaw}deg`, latitude: `${row.pitch}deg` },
        circle: 12,
        hoverScale: 1.35,
        tooltip: tooltip || undefined,
        data: row
      });
    }
  }

  _getRoomMetaMapFromProject() {
    const fp = this._project?.floorplan_data;
    if (!fp || typeof fp !== 'object') return {};
    const out = {};
    if (Array.isArray(fp.rooms)) {
      for (const r of fp.rooms) {
        const roomId = String(r?.roomId || r?.id || '').trim();
        if (!roomId) continue;
        out[roomId] = { name: r?.name ?? null, status: r?.status ?? null, panoramaId: r?.panoramaId ?? null };
      }
    }
    const roomStatus = fp.room_status && typeof fp.room_status === 'object' ? fp.room_status : null;
    const roomNames = fp.room_names && typeof fp.room_names === 'object' ? fp.room_names : null;
    const roomMap = fp.room_map && typeof fp.room_map === 'object' ? fp.room_map : null;
    if (roomStatus) for (const [roomId, status] of Object.entries(roomStatus)) out[roomId] = { ...(out[roomId] || {}), status: status ?? null };
    if (roomNames) for (const [roomId, name] of Object.entries(roomNames)) out[roomId] = { ...(out[roomId] || {}), name: name ?? null };
    if (roomMap) for (const [roomId, panoramaId] of Object.entries(roomMap)) out[roomId] = { ...(out[roomId] || {}), panoramaId: panoramaId ?? null };
    return out;
  }

  _getRoomIdForPanorama(pano) {
    if (!pano) return null;
    const map = this._project?.floorplan_data?.room_map || null;
    if (!map || typeof map !== 'object') return null;
    const panoId = pano?.id ? String(pano.id) : '';
    const panoName = pano?.name ? String(pano.name) : '';
    const panoUrl = pano?.image_url ? String(pano.image_url) : '';
    const panoUrlNoQuery = panoUrl.split('?')[0];
    const panoFile = panoUrl ? panoUrl.split('/').pop() : '';
    const panoFileNoQuery = panoFile.split('?')[0];
    for (const [roomId, ref] of Object.entries(map)) {
      if (!ref) continue;
      const v = String(ref);
      const vNoQuery = v.split('?')[0];
      const vFile = v.split('/').pop() || v;
      const vFileNoQuery = vFile.split('?')[0];
      if (
        v === panoId ||
        v === panoName ||
        v === panoFile ||
        v === panoFileNoQuery ||
        v === panoUrl ||
        vNoQuery === panoUrlNoQuery ||
        vFileNoQuery === panoFileNoQuery
      ) return roomId;
    }
    return null;
  }

  // -----------------------------
  // HUD + overlay (minimal, keeps existing CSS classes)
  // -----------------------------

  _createHud() {
    const hud = document.createElement('div');
    hud.className = 'p360-hud';

    // Left interiors
    const left = document.createElement('div');
    left.className = 'p360-hud-left';
    const leftTitle = document.createElement('div');
    leftTitle.className = 'p360-hud-left-title';
    leftTitle.textContent = 'Interiors';
    const leftList = document.createElement('div');
    leftList.className = 'p360-hud-left-list';
    left.appendChild(leftTitle);
    left.appendChild(leftList);
    hud.appendChild(left);

    // Right mode buttons
    const right = document.createElement('div');
    right.className = 'p360-hud-right';
    const mkModeBtn = (label, mode, cls) => {
      const b = document.createElement('button');
      b.type = 'button';
      b.className = `p360-btn p360-btn-mode ${cls}`;
      b.textContent = label;
      b.addEventListener('click', () => this._setViewMode(mode));
      return b;
    };
    this._btnMode360 = mkModeBtn('360', '360', 'p360-btn-mode-360');
    this._btnMode3d = mkModeBtn('3D', '3d', 'p360-btn-mode-3d');
    this._btnMode2d = mkModeBtn('2D', '2d', 'p360-btn-mode-2d');
    right.appendChild(this._btnMode360);
    right.appendChild(this._btnMode3d);
    right.appendChild(this._btnMode2d);
    hud.appendChild(right);

    // Top-right fullscreen
    const topRight = document.createElement('div');
    topRight.className = 'p360-hud-topright';
    const fs = document.createElement('button');
    fs.type = 'button';
    fs.className = 'p360-btn p360-btn-fullscreen';
    fs.title = 'Fullscreen';
    fs.addEventListener('click', () => this._toggleFullscreen());
    topRight.appendChild(fs);
    hud.appendChild(topRight);

    // Bottom pill (zoom + autorotate + VR)
    const bottom = document.createElement('div');
    bottom.className = 'p360-hud-bottom p360-hud-bottom-pill';

    const mkPill = (title, cls, onClick) => {
      const b = document.createElement('button');
      b.type = 'button';
      b.className = `p360-btn p360-btn-pill ${cls}`;
      b.title = title;
      b.addEventListener('click', onClick);
      return b;
    };

    const zoom = mkPill('Zoom', 'p360-btn-zoom', () => this._cycleZoom());
    zoom.textContent = '1×';
    this._btnZoom = zoom;

    const rotate = mkPill('Auto-rotate', 'p360-btn-autorotate', () => this._toggleAutorotate());
    this._btnAutorotate = rotate;

    const vr = mkPill('VR', 'p360-btn-vr', () => this.enterVR().catch(() => {}));
    vr.textContent = 'VR';
    this._btnVr = vr;

    bottom.appendChild(zoom);
    bottom.appendChild(rotate);
    bottom.appendChild(vr);
    hud.appendChild(bottom);

    this.container.appendChild(hud);
    this._hudLeftList = leftList;
    this._buildInteriorButtons();

    this._updateHudState = () => {
      this._btnMode360?.classList.toggle('is-active', this._viewMode === '360');
      this._btnMode2d?.classList.toggle('is-active', this._viewMode === '2d');
      this._btnMode3d?.classList.toggle('is-active', this._viewMode === '3d');
      for (const [name, btn] of this._hudInteriorButtons.entries()) {
        btn.classList.toggle('is-active', name === this._interior);
      }
    };

    return hud;
  }

  _buildInteriorButtons() {
    if (!this._hudLeftList) return;
    this._hudLeftList.innerHTML = '';
    this._hudInteriorButtons.clear();
    for (const name of this._interiors || []) {
      const b = document.createElement('button');
      b.type = 'button';
      b.className = 'p360-btn p360-btn-interior';
      b.textContent = name;
      b.addEventListener('click', () => this._setInterior(name));
      this._hudLeftList.appendChild(b);
      this._hudInteriorButtons.set(name, b);
    }
  }

  _createOverlay() {
    const wrap = document.createElement('div');
    wrap.className = 'p360-overlay';
    wrap.style.display = 'none';

    const img = document.createElement('img');
    img.className = 'p360-overlay-img';
    img.alt = 'Overlay';
    wrap.appendChild(img);

    const pager = document.createElement('div');
    pager.className = 'p360-overlay-pager';
    const prev = document.createElement('button');
    prev.className = 'p360-overlay-pager-btn';
    prev.textContent = '‹';
    const next = document.createElement('button');
    next.className = 'p360-overlay-pager-btn';
    next.textContent = '›';
    const count = document.createElement('div');
    count.className = 'p360-overlay-pager-count';
    pager.appendChild(prev);
    pager.appendChild(count);
    pager.appendChild(next);
    wrap.appendChild(pager);

    prev.addEventListener('click', () => this._navOverlay(-1));
    next.addEventListener('click', () => this._navOverlay(1));

    this.container.appendChild(wrap);
    return {
      wrap,
      img,
      count,
      setVisible: (v) => { wrap.style.display = v ? '' : 'none'; },
      setLoading: (v) => { wrap.classList.toggle('is-loading', !!v); }
    };
  }

  _applyOverlayMode(mode) {
    const urls = mode === '2d' ? (this._middleCutUrls || []) : (this._topViewUrl ? [this._topViewUrl] : []);
    this._overlayUrls = urls;
    this._overlayIndex = 0;
    this._overlay.setVisible(true);
    this._psvEl.style.display = 'none';
    this._renderOverlay();
  }

  _renderOverlay() {
    const u = this._overlayUrls?.[this._overlayIndex] || null;
    if (!u) return;
    this._overlay.img.src = u;
    this._overlay.count.textContent = `${this._overlayIndex + 1}/${this._overlayUrls.length || 1}`;
  }

  _navOverlay(dir) {
    if (!this._overlayUrls?.length) return;
    const n = this._overlayUrls.length;
    this._overlayIndex = (this._overlayIndex + dir + n) % n;
    this._renderOverlay();
  }

  _setViewMode(mode) {
    this._viewMode = mode;
    if (mode === '360') {
      this._overlay.setVisible(false);
      this._psvEl.style.display = '';
    } else {
      this._applyOverlayMode(mode);
    }
    this._updateHudState?.();
  }

  async _setInterior(name) {
    if (!name || name === this._interior) return;
    const prevId = this._currentPanoramaId;
    const keepFile = prevId ? String(prevId) : null;
    this._interior = name;
    this._panoramas = this._buildPanoramasForInterior(this._interior);
    this._topViewUrl = this._inferTopViewUrl();
    this._middleCutUrls = await this._inferMiddleCutUrls();
    this._buildInteriorButtons();
    this._updateHudState?.();
    const keep = keepFile && this._getPanoramaById(keepFile) ? keepFile : (this._panoramas?.[0]?.id || null);
    if (keep) await this.loadPanorama(keep, { reason: 'interior' });
  }

  async _toggleFullscreen() {
    const el = this.container;
    const doc = document;
    const isFs = doc.fullscreenElement === el;
    if (!isFs) await el.requestFullscreen?.({ navigationUI: 'hide' });
    else await doc.exitFullscreen?.();
  }

  _toggleAutorotate() {
    if (!this._psv) return;
    if (typeof this._psv.toggleAutorotate === 'function') this._psv.toggleAutorotate();
    else if (typeof this._psv.startAutorotate === 'function') this._psv.startAutorotate();
  }

  _cycleZoom() {
    if (!this._psv) return;
    const levels = [0, 50, 100];
    let cur = 0;
    try { cur = this._psv.getZoomLevel?.() ?? 0; } catch {}
    const idx = levels.reduce((best, v, i) => (Math.abs(v - cur) < Math.abs(levels[best] - cur) ? i : best), 0);
    const next = levels[(idx + 1) % levels.length];
    try { this._psv.zoom?.(next); } catch {}
    if (this._btnZoom) this._btnZoom.textContent = next === 0 ? '1×' : (next === 50 ? '1.5×' : '2×');
  }

  async _onFloorplanNavigate(panoramaId) {
    await this.analytics.track('floorplan_click', { panoramaId });
    await this.loadPanorama(panoramaId, { reason: 'floorplan' });
  }

  async _onFloorplanRoomClick(roomId) {
    const info =
      typeof roomId === 'string'
        ? { roomId, roomName: null, panoramaId: null }
        : (roomId || { roomId: null, roomName: null, panoramaId: null });
    const rid = info?.roomId || null;
    if (!rid) return;
    const map = this._project?.floorplan_data?.room_map || null;
    const mappedId = map && typeof map === 'object' ? map[rid] : null;
    const pano = mappedId ? this._getPanoramaById(mappedId) : (this._panoramas.find((p) => p.room_id === rid) || null);
    if (pano?.id) await this.loadPanorama(pano.id, { reason: 'floorplan_room' });
  }

  _onFloorplanRoomHover(room) {
    void room;
  }

  _inferTopViewUrl() {
    const interior = this._interior;
    const candidates = [
      ...this._getProjectImages('3d', interior),
      ...this._getProjectImages('2d', interior),
      ...this._getProjectImages('3d', null),
      ...this._getProjectImages('2d', null)
    ];
    for (const a of candidates) {
      const name = this._getAssetName(a) || '';
      const url = this._getAssetUrl(a);
      if (!url) continue;
      if (name.startsWith('TopView_') || name.includes('/TopView_') || name.includes('TopView_')) return url;
    }
    return null;
  }

  async _inferMiddleCutUrls() {
    const interior = this._interior;
    const candidates = [
      ...this._getProjectImages('2d', interior),
      ...this._getProjectImages('2d', null)
    ];
    const assetUrls = candidates
      .map((a) => {
        const name = this._getAssetName(a) || '';
        const url = this._getAssetUrl(a);
        if (!url) return null;
        if (!name.includes('MiddleCut_') && !name.startsWith('MiddleCut_')) return null;
        if (!/\.(webp|jpe?g|png)$/i.test(name.split('?')[0] || name)) return null;
        return { name, url };
      })
      .filter(Boolean)
      .slice()
      .sort((a, b) => String(a.name).localeCompare(String(b.name)))
      .map((x) => x.url);
    return assetUrls;
  }
}

